from beeai import Swarm
from beeai.events import EventType

class CoordinationMonitor:
    def __init__(self):
        self.pending_handoffs = {}
        self.timeout = 30  # seconds

    def on_agent_event(self, event):
        if event.type == EventType.TASK_HANDOFF:
            agent_id = event.source_agent
            task_id = event.payload['task_id']
            self.pending_handoffs[(agent_id, task_id)] = time.time()

        elif event.type == EventType.TASK_ACCEPTED:
            task_id = event.payload['task_id']
            for (sender, tid), timestamp in list(self.pending_handoffs.items()):
                if tid == task_id and time.time() - timestamp > self.timeout:
                    print(f'🚨 COORDINATION FAILURE: Handoff timeout from {sender} for {task_id}')
                    del self.pending_handoffs[(sender, tid)]

monitor = CoordinationMonitor()
swarm = Swarm(event_listener=monitor.on_agent_event)

from beeai.agents import AgentMemory

def detect_memory_divergence(swarm):
    checkpoint_keys = ['workflow_state', 'task_dependencies', 'agent_roles']

    for agent in swarm.active_agents:
        memory = agent.get_memory()
        missing_checkpoints = [k for k in checkpoint_keys if k not in memory]

        if missing_checkpoints:
            divergence_score = len(missing_checkpoints) / len(checkpoint_keys)
            if divergence_score > 0.5:
                print(f'🚨 MEMORY DIVERGENCE: Agent {agent.id} missing {missing_checkpoints}')
                print(f'   Current state hash: {hash(str(memory))}')

    return {'divergent_agents': len([a for a in swarm.active_agents if detect_memory_divergence(a) > 0.5])}

