from beeai.agents import AgentMemory
from beeai.swarm import SwarmLock

class SyncBarrier:
    @staticmethod
    def sync_before_handoff(swarm, checkpoint_keys):
        with SwarmLock(swarm):
            for agent in swarm.active_agents:
                memory = agent.get_memory()
                # Validate required checkpoints exist
                for key in checkpoint_keys:
                    if key not in memory:
                        raise CoordinationError(f'Missing checkpoint {key} in {agent.id}')

                # Broadcast consistent memory snapshot
                agent.set_memory({'sync_timestamp': time.time(), **memory})
        print('✅ Memory sync barrier passed')

# Usage before handoff
SyncBarrier.sync_before_handoff(swarm, ['current_task', 'dependencies', 'role'])
